import{_ as t,o,c as n,a2 as a}from"./chunks/framework.B72_uj9U.js";const m=JSON.parse('{"title":"Chapter 6: Shell Execution","description":"Spawning processes, capturing output, and implementing a shell execution tool with safety and timeout handling.","frontmatter":{"title":"Chapter 6: Shell Execution","description":"Spawning processes, capturing output, and implementing a shell execution tool with safety and timeout handling."},"headers":[],"relativePath":"learn/project/06-shell-execution/index.md","filePath":"learn/project/06-shell-execution/index.md"}'),i={name:"learn/project/06-shell-execution/index.md"};function r(s,e,l,c,d,u){return o(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="shell-execution" tabindex="-1">Shell Execution <a class="header-anchor" href="#shell-execution" aria-label="Permalink to &quot;Shell Execution&quot;">​</a></h1><p>One of the most powerful capabilities an AI coding agent can have is the ability to execute shell commands. Running <code>cargo test</code>, <code>git diff</code>, <code>grep -r</code>, or any arbitrary command transforms your agent from a text-processing assistant into a genuine coding partner that can observe the real state of a project and take action on it.</p><p>This chapter takes you through the full journey of building a robust shell execution tool in Rust, from the fundamentals of process spawning to advanced concerns like sandboxing and dangerous command detection. You will learn how to use Rust&#39;s <code>std::process::Command</code> and Tokio&#39;s async process APIs to spawn child processes, capture their stdout and stderr streams, and enforce timeouts so your agent never hangs on a runaway command. We cover environment variable injection, working directory management, and output truncation strategies that keep context windows lean.</p><p>Safety is paramount when giving an AI agent shell access. An unchecked <code>rm -rf /</code> or a <code>curl | bash</code> piped from the internet could be catastrophic. You will implement a layered defense strategy including sandboxing basics, dangerous command detection heuristics, and configurable allow/deny lists. By the end of this chapter, you will have a production-quality shell execution tool integrated into your agent&#39;s tool system, complete with a comprehensive test suite.</p><h2 id="learning-objectives" tabindex="-1">Learning Objectives <a class="header-anchor" href="#learning-objectives" aria-label="Permalink to &quot;Learning Objectives&quot;">​</a></h2><ul><li>Spawn and manage child processes using Rust&#39;s standard library and Tokio</li><li>Capture and separate stdout and stderr streams from executed commands</li><li>Implement timeout enforcement and signal handling for long-running processes</li><li>Build a command builder abstraction with environment and working directory control</li><li>Detect and block dangerous commands before execution</li><li>Truncate oversized output to stay within LLM context window limits</li><li>Write integration tests for shell tool behavior including edge cases</li></ul><h2 id="subchapters" tabindex="-1">Subchapters <a class="header-anchor" href="#subchapters" aria-label="Permalink to &quot;Subchapters&quot;">​</a></h2><ol><li><a href="/project/06-shell-execution/01-process-spawning.html">Process Spawning</a> -- spawn child processes with <code>std::process::Command</code> and Tokio&#39;s async equivalent</li><li><a href="/project/06-shell-execution/02-stdout-stderr-capture.html">Stdout Stderr Capture</a> -- pipe and collect output streams into structured results</li><li><a href="/project/06-shell-execution/03-command-builder.html">Command Builder</a> -- design a fluent builder for configuring shell commands</li><li><a href="/project/06-shell-execution/04-timeouts.html">Timeouts</a> -- prevent runaway processes with <code>tokio::time::timeout</code></li><li><a href="/project/06-shell-execution/05-signal-handling.html">Signal Handling</a> -- send SIGTERM/SIGKILL and manage process groups</li><li><a href="/project/06-shell-execution/06-environment-variables.html">Environment Variables</a> -- control variable inheritance and injection</li><li><a href="/project/06-shell-execution/07-working-directory.html">Working Directory</a> -- run commands in the correct project context</li><li><a href="/project/06-shell-execution/08-sandboxing-basics.html">Sandboxing Basics</a> -- restrict filesystem and network access for spawned processes</li><li><a href="/project/06-shell-execution/09-output-truncation.html">Output Truncation</a> -- keep command output within context window limits</li><li><a href="/project/06-shell-execution/10-dangerous-command-detection.html">Dangerous Command Detection</a> -- detect and block destructive command patterns</li><li><a href="/project/06-shell-execution/11-testing-shell-tool.html">Testing Shell Tool</a> -- unit and integration tests for the complete shell tool</li><li><a href="/project/06-shell-execution/12-summary.html">Summary</a> -- review the full implementation and safety design</li></ol><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>Chapter 4: Tool system architecture and the <code>Tool</code> trait</li><li>Chapter 5: File operation tools and permission patterns</li><li>Basic familiarity with terminal commands (<code>ls</code>, <code>echo</code>, <code>grep</code>, etc.)</li></ul>',10)])])}const p=t(i,[["render",r]]);export{m as __pageData,p as default};
